import { initializeApp } from "firebase/app";
import { initializeFirestore, enableIndexedDbPersistence } from "firebase/firestore";
import firebaseConfig from "../firebase-applet-config.json";

// Initialize Firebase using the configuration generated by the platform
const app = initializeApp(firebaseConfig);

// Initialize Cloud Firestore with custom database ID from configuration and long polling enabled for proxies/iframes
export const db = initializeFirestore(app, {
  experimentalForceLongPolling: true
}, firebaseConfig.firestoreDatabaseId || "(default)");

// Enable offline persistence to handle connectivity drops and offline caching seamlessly
if (typeof window !== "undefined") {
  enableIndexedDbPersistence(db).catch((err) => {
    if (err.code === "failed-precondition") {
      // Multiple tabs open, persistence can only be enabled in one tab at a time.
      console.warn("Firestore offline persistence failed-precondition: multiple tabs open.");
    } else if (err.code === "unimplemented") {
      // The current browser does not support all of the features required to enable persistence
      console.warn("Firestore offline persistence unimplemented in this browser.");
    } else {
      console.warn("Firestore offline persistence error:", err);
    }
  });
}
